det_check_template:
proof fn det_init<const N: usize>(pre_self_: ArraySet<N>, post1_self_: ArraySet<N>, r1: (), post2_self_: ArraySet<N>, r2: ())
    requires (pre_self_.wf()),
    ensures
        ({
            &&& (post1_self_.wf())
            &&& (post1_self_@ == Set::<usize>::empty())
            &&& (post2_self_.wf())
            &&& (post2_self_@ == Set::<usize>::empty())
        }) ==> det_init_equal(r1, r2, post1_self_, post2_self_),
{
{ASSUMES}}

